    """Detect the VCS backend for a directory.

    Detection order: DataLad -> GitAnnex -> Git -> NoVCS
    """
    git_dir = root / ".git"
    if not git_dir.exists():
        return NoVCS(root)

    # Check for DataLad
    datalad_dir = root / ".datalad"
    if datalad_dir.is_dir():
