    # Check for git-annex
    try:
        result = subprocess.run(
            ["git", "config", "--get", "annex.uuid"],
            cwd=root,
            capture_output=True,
            text=True,
        )
        if result.returncode == 0 and result.stdout.strip():
            return GitAnnex(root)
    except FileNotFoundError:
        pass

    return Git(root)

